export function getModelMapping(modelId: string): ModelMapping | undefined {
  return MODEL_MAPPINGS[modelId];
}

export function getProviderForModelId(modelId: string): ModelProvider | undefined {
  return MODEL_MAPPINGS[modelId]?.provider;
}

export function getValidModelsForProvider(provider: ModelProvider): string[] {
  return Object.values(MODEL_MAPPINGS)
    .filter((m) => m.provider === provider)
    .map((m) => m.model);
}

export function getAnthropicModelForModelId(modelId: string): string | undefined {
  const mapping = MODEL_MAPPINGS[modelId];
  return mapping?.provider === 'anthropic' ? mapping.model : undefined;
}

export function getOpenAIModelForModelId(modelId: string): string | undefined {
  const mapping = MODEL_MAPPINGS[modelId];
  return mapping?.provider === 'openai' ? mapping.model : undefined;
}

export function getOpenAIApiType(modelId: string): OpenAIApiType {
  const mapping = MODEL_MAPPINGS[modelId];
  return mapping?.openaiApiType ?? 'chat';
}

export function isResponsesApiModel(modelId: string): boolean {
  return getOpenAIApiType(modelId) === 'responses';
}

export function isWorkflowModel(modelId: string): boolean {
  return MODEL_MAPPINGS[modelId]?.provider === 'workflow';
}

export function getWorkflowModelRef(modelId: string): string | undefined {
  const mapping = MODEL_MAPPINGS[modelId];
  return mapping?.provider === 'workflow' ? mapping.model : undefined;
}

export const MODEL_ID_TO_ANTHROPIC_MODEL: Record<string, string> = Object.fromEntries(
  Object.entries(MODEL_MAPPINGS)
    .filter(([, v]) => v.provider === 'anthropic')
    .map(([k, v]) => [k, v.model])
);
